  1‚Üíimport { useRef, useCallback, useEffect, useState, useMemo } from 'react';
  2‚Üíimport { useEditor } from '@/app/EditorProvider';
  3‚Üíimport { useProject } from '@/app/ProjectProvider';
  4‚Üíimport { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5‚Üíimport { normalizeRectBounds } from '@/clipboard/planClipboard';
  6‚Üíimport { getFloorElevation } from '@/domain/floorModels';
  7‚Üíimport { resolveRoofSectionCut } from '@/domain/roofModels';
  8‚Üíimport { filterProjectByPhase } from '@/domain/phaseFilter';
  9‚Üíimport { usePhaseFilteredFloor } from '@/hooks/usePhaseFilteredFloor';
 10‚Üíimport { useEditorTool } from '@/editor/useEditorTool';
 11‚Üíimport { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
 12‚Üíimport { formatSurveyorBearing, pointsToSurveyorBearing } from '@/geometry/bearing';
 13‚Üíimport { TOOLS } from '@/editor/tools';
 14‚Üíimport ClipboardPreviewLayer from './ClipboardPreviewLayer';
 15‚Üíimport CompassOverlay from '@/ui/CompassOverlay';
 16‚Üíimport GridRenderer from './GridRenderer';
 17‚Üíimport SlabRenderer from './SlabRenderer';
 18‚Üíimport WallRenderer from './WallRenderer';
 19‚Üíimport BeamRenderer from './BeamRenderer';
 20‚Üíimport StairRenderer from './StairRenderer';
 21‚Üíimport DoorRenderer from './DoorRenderer';
 22‚Üíimport WindowRenderer from './WindowRenderer';
 23‚Üíimport RoomRenderer from './RoomRenderer';
 24‚Üíimport AnnotationRenderer from './AnnotationRenderer';
 25‚Üíimport ElevationRenderer from './ElevationRenderer';
 26‚Üíimport SectionRenderer from './SectionRenderer';
 27‚Üíimport SelectionOverlay from './SelectionOverlay';
 28‚Üíimport DimensionPreview from './DimensionPreview';
 29‚Üíimport WallPreview from './WallPreview';
 30‚Üíimport LandingRenderer from './LandingRenderer';
 31‚Üíimport LandingPreview from './LandingPreview';
 32‚Üíimport ColumnRenderer from './ColumnRenderer';
 33‚Üíimport ColumnPreview from './ColumnPreview';
 34‚Üíimport FixtureDefs from './FixtureDefs';
 35‚Üíimport FixtureRenderer from './FixtureRenderer';
 36‚Üíimport FixturePreview from './FixturePreview';
 37‚Üíimport BeamPreview from './BeamPreview';
 38‚Üíimport StairPreview from './StairPreview';
 39‚Üíimport SlabPreview from './SlabPreview';
 40‚Üíimport DoorWindowPreview from './DoorWindowPreview';
 41‚Üíimport RoomPreview from './RoomPreview';
 42‚Üíimport SectionCutRenderer from './SectionCutRenderer';
 43‚Üíimport SectionCutPreview from './SectionCutPreview';
 44‚Üíimport RailingRenderer from './RailingRenderer';
 45‚Üíimport RailingPreview from './RailingPreview';
 46‚Üíimport RegionSelectionOverlay from './RegionSelectionOverlay';
 47‚Üíimport RoofRenderer from './RoofRenderer';
 48‚Üíimport RoofElevationRenderer from './RoofElevationRenderer';
 49‚Üíimport RoofSectionRenderer from './RoofSectionRenderer';
 50‚Üíimport RoofSelectionOverlay from './RoofSelectionOverlay';
 51‚Üíimport RoofPreviewLayer from './RoofPreviewLayer';
 52‚Üíimport TrussRenderer from './TrussRenderer';
 53‚Üíimport TrussSelectionOverlay from './TrussSelectionOverlay';
 54‚Üíimport TrussDrawOverlay from './TrussDrawOverlay';
 55‚Üíimport TrussDetailRenderer from './TrussDetailRenderer';
 56‚Üíimport TrussSectionRenderer from './TrussSectionRenderer';
 57‚Üíimport { CenterViewIcon, ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 58‚Üíimport { isTypingTarget } from '@/utils/keyboard';
 59‚Üíimport styles from './SvgCanvas.module.css';
 60‚Üí
 61‚Üífunction screenToModel(screenX, screenY, viewport, svgRect) {
 62‚Üí  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 63‚Üí  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 64‚Üí  return { x, y };
 65‚Üí}
 66‚Üí
 67‚Üíexport default function SvgCanvas() {
 68‚Üí  const svgRef = useRef(null);
 69‚Üí  const isPanning = useRef(false);
 70‚Üí  const lastPanPos = useRef({ x: 0, y: 0 });
 71‚Üí  const spaceHeld = useRef(false);
 72‚Üí  const cursorPosRef = useRef({ x: 0, y: 0 });
 73‚Üí  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 74‚Üí
 75‚Üí  const { project, dispatch, getFloor } = useProject();
 76‚Üí  const editor = useEditor();
 77‚Üí  const {
 78‚Üí    activeTool, selectedId, selectedType, toolState,
 79‚Üí    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 80‚Üí    regionSelection, pastePreview, maximizedPanel,
 81‚Üí    modelTarget,
 82‚Üí    activePhaseId, phaseViewMode,
 83‚Üí    dispatch: editorDispatch,
 84‚Üí  } = editor;
 85‚Üí
 86‚Üí  const floor = getFloor(activeFloorId);
 87‚Üí  const filteredFloor = usePhaseFilteredFloor(floor, project, activePhaseId, phaseViewMode);
 88‚Üí  const filteredProject = useMemo(
 89‚Üí    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 90‚Üí    [project, activePhaseId, phaseViewMode]
 91‚Üí  );
 92‚Üí  const roofSystem = filteredProject.roofSystem || null;
 93‚Üí  const roofHiddenByPhase = Boolean(project.roofSystem && !roofSystem);
 94‚Üí  const floorTrussSystems = (filteredProject.trussSystems || []).filter((trussSystem) => trussSystem.floorId === activeFloorId);
 95‚Üí  const activeTrussContext = useMemo(() => {
 96‚Üí    if (selectedType === 'trussSystem') {
 97‚Üí      const trussSystem = (filteredProject.trussSystems || []).find((entry) => entry.id === selectedId) || null;
 98‚Üí      return {
 99‚Üí        trussSystem,
100‚Üí        trussInstanceId: null,
101‚Üí      };
102‚Üí    }
103‚Üí    if (selectedType === 'trussInstance') {
104‚Üí      const trussSystem = (filteredProject.trussSystems || []).find((entry) => (
105‚Üí        (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
106‚Üí      )) || null;
107‚Üí      return {
108‚Üí        trussSystem,
109‚Üí        trussInstanceId: selectedId,
110‚Üí      };
111‚Üí    }
112‚Üí    return {
113‚Üí      trussSystem: floorTrussSystems[0] || null,
114‚Üí      trussInstanceId: floorTrussSystems[0]?.trussInstances?.[0]?.id || null,
115‚Üí    };
116‚Üí  }, [filteredProject.trussSystems, floorTrussSystems, selectedId, selectedType]);
117‚Üí  const {
118‚Üí    copySelection,
119‚Üí    cutSelection,
120‚Üí    beginPaste,
121‚Üí    updatePastePreview,
122‚Üí    cancelPaste,
123‚Üí    placePaste,
124‚Üí    previewContent,
125‚Üí  } = usePlanClipboardController();
126‚Üí
127‚Üí  const tool = useEditorTool({
128‚Üí    activeTool,
129‚Üí    dispatch,
130‚Üí    editorDispatch,
131‚Üí    project,
132‚Üí    getFloor,
133‚Üí    activeFloorId,
134‚Üí    roofSystem,
135‚Üí    trussSystems: floorTrussSystems,
136‚Üí    modelTarget,
137‚Üí    viewport,
138‚Üí    snapEnabled,
139‚Üí    selectedId,
140‚Üí    selectedType,
141‚Üí    toolState,
142‚Üí    viewMode,
143‚Üí    activePhaseId,
144‚Üí  });
145‚Üí
146‚Üí  const getModelPos = useCallback((e) => {
147‚Üí    const rect = svgRef.current.getBoundingClientRect();
148‚Üí    return screenToModel(e.clientX, e.clientY, viewport, rect);
149‚Üí  }, [viewport]);
150‚Üí
151‚Üí  const handleMouseDown = useCallback((e) => {
152‚Üí    // Middle mouse or space+left for pan
153‚Üí    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
154‚Üí      isPanning.current = true;
155‚Üí      lastPanPos.current = { x: e.clientX, y: e.clientY };
156‚Üí      e.preventDefault();
157‚Üí      return;
158‚Üí    }
159‚Üí
160‚Üí    const modelPos = getModelPos(e);
161‚Üí    if (modelTarget === 'floor' && pastePreview?.active && e.button === 0) {
162‚Üí      placePaste(modelPos);
163‚Üí      return;
164‚Üí    }
165‚Üí    tool.onMouseDown(modelPos, e);
166‚Üí  }, [getModelPos, modelTarget, pastePreview, placePaste, tool]);
167‚Üí
168‚Üí  const handleMouseMove = useCallback((e) => {
169‚Üí    if (isPanning.current) {
170‚Üí      const dx = e.clientX - lastPanPos.current.x;
171‚Üí      const dy = e.clientY - lastPanPos.current.y;
172‚Üí      editorDispatch({ type: 'PAN', dx, dy });
173‚Üí      lastPanPos.current = { x: e.clientX, y: e.clientY };
174‚Üí      return;
175‚Üí    }
176‚Üí
177‚Üí    const modelPos = getModelPos(e);
178‚Üí    cursorPosRef.current = modelPos;
179‚Üí    setCursorPos(modelPos);
180‚Üí    if (modelTarget === 'floor' && pastePreview?.active) {
181‚Üí      updatePastePreview(modelPos);
182‚Üí      return;
183‚Üí    }
184‚Üí    tool.onMouseMove(modelPos, e);
185‚Üí  }, [getModelPos, modelTarget, pastePreview, tool, updatePastePreview, editorDispatch]);
186‚Üí
187‚Üí  const handleMouseUp = useCallback((e) => {
188‚Üí    if (isPanning.current) {
189‚Üí      isPanning.current = false;
190‚Üí      return;
191‚Üí    }
192‚Üí    if (modelTarget === 'floor' && pastePreview?.active) return;
193‚Üí    const modelPos = getModelPos(e);
194‚Üí    tool.onMouseUp(modelPos, e);
195‚Üí  }, [getModelPos, modelTarget, pastePreview, tool]);
196‚Üí
197‚Üí  const handleDoubleClick = useCallback((e) => {
198‚Üí    if (modelTarget === 'floor' && pastePreview?.active) return;
199‚Üí    const modelPos = getModelPos(e);
200‚Üí    tool.onDoubleClick(modelPos, e);
201‚Üí  }, [getModelPos, modelTarget, pastePreview, tool]);
202‚Üí
203‚Üí  const handleWheel = useCallback((e) => {
204‚Üí    e.preventDefault();
205‚Üí    const rect = svgRef.current.getBoundingClientRect();
206‚Üí    const mouseX = e.clientX - rect.left;
207‚Üí    const mouseY = e.clientY - rect.top;
208‚Üí
209‚Üí    const direction = e.deltaY < 0 ? 1 : -1;
210‚Üí    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
211‚Üí    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
212‚Üí
213‚Üí    // Zoom centered on cursor
214‚Üí    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
215‚Üí    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
216‚Üí
217‚Üí    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
218‚Üí  }, [viewport, editorDispatch]);
219‚Üí
220‚Üí  const handleResetCenterPoint = useCallback(() => {
221‚Üí    const rect = svgRef.current?.getBoundingClientRect();
222‚Üí    if (!rect) return;
223‚Üí
224‚Üí    editorDispatch({
225‚Üí      type: 'SET_VIEWPORT',
226‚Üí      viewport: {
227‚Üí        ...viewport,
228‚Üí        panX: rect.width / 2,
229‚Üí        panY: rect.height / 2,
230‚Üí      },
231‚Üí    });
232‚Üí  }, [editorDispatch, viewport]);
233‚Üí
234‚Üí  useEffect(() => {
235‚Üí    if (!statusMessage) return undefined;
236‚Üí
237‚Üí    const timer = window.setTimeout(() => {
238‚Üí      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
239‚Üí    }, 2500);
240‚Üí
241‚Üí    return () => window.clearTimeout(timer);
242‚Üí  }, [statusMessage, editorDispatch]);
243‚Üí
244‚Üí  useEffect(() => {
245‚Üí    const handleKeyDown = (e) => {
246‚Üí      if (isTypingTarget(e.target)) return;
247‚Üí
248‚Üí      if (e.key === ' ') {
249‚Üí        spaceHeld.current = true;
250‚Üí        e.preventDefault();
251‚Üí      }
252‚Üí
253‚Üí      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan' && modelTarget === 'floor') {
254‚Üí        const key = e.key.toLowerCase();
255‚Üí        if (key === 'c') {
256‚Üí          e.preventDefault();
257‚Üí          copySelection();
258‚Üí          return;
259‚Üí        }
260‚Üí        if (key === 'x') {
261‚Üí          e.preventDefault();
262‚Üí          cutSelection();
263‚Üí          return;
264‚Üí        }
265‚Üí        if (key === 'v') {
266‚Üí          e.preventDefault();
267‚Üí          beginPaste(cursorPosRef.current);
268‚Üí          return;
269‚Üí        }
270‚Üí      }
271‚Üí
272‚Üí      if (e.key === 'Escape' && modelTarget === 'floor' && pastePreview?.active) {
273‚Üí        e.preventDefault();
274‚Üí        cancelPaste();
275‚Üí        return;
276‚Üí      }
277‚Üí
278‚Üí      // Tool shortcuts
279‚Üí      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
280‚Üí        if (modelTarget === 'roof') {
281‚Üí          switch (e.key.toLowerCase()) {
282‚Üí            case 'v':
283‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
284‚Üí              return;
285‚Üí            case 'p':
286‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_PARAPET });
287‚Üí              return;
288‚Üí            case 'g':
289‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_DRAIN });
290‚Üí              return;
291‚Üí            case 'o':
292‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_OPENING });
293‚Üí              return;
294‚Üí          }
295‚Üí        } else if (modelTarget === 'truss') {
296‚Üí          switch (e.key.toLowerCase()) {
297‚Üí            case 'v':
298‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
299‚Üí              return;
300‚Üí            case 't': {
301‚Üí              const targetTrussSystem = selectedType === 'trussSystem'
302‚Üí                ? floorTrussSystems.find((entry) => entry.id === selectedId) || null
303‚Üí                : selectedType === 'trussInstance'
304‚Üí                  ? floorTrussSystems.find((entry) => (
305‚Üí                      (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
306‚Üí                    )) || null
307‚Üí                  : null;
308‚Üí              const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
309‚Üí                ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
310‚Üí                : null;
311‚Üí              const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
312‚Üí                ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
313‚Üí                : null;
314‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.TRUSS_DRAW });
315‚Üí              editorDispatch({
316‚Üí                type: 'UPDATE_TOOL_STATE',
317‚Üí                payload: {
318‚Üí                  targetTrussSystemId: targetTrussSystem?.id || null,
319‚Üí                  trussTypeId: selectedTrussInstance?.trussTypeId
320‚Üí                    || lastSystemInstance?.trussTypeId
321‚Üí                    || null,
322‚Üí                  trussMaterial: selectedTrussInstance?.material
323‚Üí                    || lastSystemInstance?.material
324‚Üí                    || null,
325‚Üí                },
326‚Üí              });
327‚Üí              return;
328‚Üí            }
329‚Üí          }
330‚Üí        } else {
331‚Üí          switch (e.key.toLowerCase()) {
332‚Üí            case 'v':
333‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
334‚Üí              return;
335‚Üí            case 'm':
336‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
337‚Üí              return;
338‚Üí            case 'w':
339‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
340‚Üí              return;
341‚Üí            case 'b':
342‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
343‚Üí              return;
344‚Üí            case 't':
345‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
346‚Üí              return;
347‚Üí            case 'q':
348‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
349‚Üí              return;
350‚Üí            case 's':
351‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
352‚Üí              return;
353‚Üí            case 'r':
354‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
355‚Üí              return;
356‚Üí            case 'd':
357‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
358‚Üí              return;
359‚Üí            case 'n':
360‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
361‚Üí              return;
362‚Üí            case 'c':
363‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
364‚Üí              return;
365‚Üí            case 'l':
366‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
367‚Üí              return;
368‚Üí            case 'h':
369‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
370‚Üí              return;
371‚Üí            case 'f':
372‚Üí              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
373‚Üí              editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
374‚Üí              return;
375‚Üí          }
376‚Üí        }
377‚Üí      }
378‚Üí
379‚Üí      tool.onKeyDown(e);
380‚Üí    };
381‚Üí
382‚Üí    const handleKeyUp = (e) => {
383‚Üí      if (isTypingTarget(e.target)) return;
384‚Üí
385‚Üí      if (e.key === ' ') {
386‚Üí        spaceHeld.current = false;
387‚Üí      }
388‚Üí    };
389‚Üí
390‚Üí    window.addEventListener('keydown', handleKeyDown);
391‚Üí    window.addEventListener('keyup', handleKeyUp);
392‚Üí    return () => {
393‚Üí      window.removeEventListener('keydown', handleKeyDown);
394‚Üí      window.removeEventListener('keyup', handleKeyUp);
395‚Üí    };
396‚Üí  }, [beginPaste, cancelPaste, copySelection, cutSelection, modelTarget, pastePreview?.active, tool, editorDispatch, viewMode, selectedId, selectedType, floorTrussSystems]);
397‚Üí
398‚Üí  // Prevent default context menu on SVG
399‚Üí  useEffect(() => {
400‚Üí    const svg = svgRef.current;
401‚Üí    if (!svg) return;
402‚Üí    const prevent = (e) => e.preventDefault();
403‚Üí    svg.addEventListener('contextmenu', prevent);
404‚Üí    svg.addEventListener('wheel', handleWheel, { passive: false });
405‚Üí    return () => {
406‚Üí      svg.removeEventListener('contextmenu', prevent);
407‚Üí      svg.removeEventListener('wheel', handleWheel);
408‚Üí    };
409‚Üí  }, [handleWheel]);
410‚Üí
411‚Üí  const cursor = spaceHeld.current ? 'grab' : (modelTarget === 'floor' && pastePreview?.active) ? 'copy' : tool.getCursor();
412‚Üí  const zoomPercent = Math.round(viewport.zoom * 1000);
413‚Üí  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
414‚Üí  const isCanvasMaximized = maximizedPanel === 'canvas';
415‚Üí  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
416‚Üí    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
417‚Üí    : null;
418‚Üí  const selectionCount = regionSelection?.objectCount || 0;
419‚Üí  const liveWallBearing = modelTarget === 'floor' && activeTool === TOOLS.WALL && toolState.start && toolState.preview
420‚Üí    ? formatSurveyorBearing(pointsToSurveyorBearing(toolState.start, toolState.preview))
421‚Üí    : null;
422‚Üí  const hasRoofSectionCut = Boolean(resolveRoofSectionCut(project, activeFloorId, activeSectionCutId).sectionCut);
423‚Üí  const hasTrussSectionCut = Boolean((floor?.sectionCuts || []).length);
424‚Üí
425‚Üí  return (
426‚Üí    <div className={styles.canvasContainer}>
427‚Üí      <CompassOverlay className={styles.compassDock} />
428‚Üí      <svg
429‚Üí        ref={svgRef}
430‚Üí        className={styles.svg}
431‚Üí        style={{ cursor }}
432‚Üí        onMouseDown={handleMouseDown}
433‚Üí        onMouseMove={handleMouseMove}
434‚Üí        onMouseUp={handleMouseUp}
435‚Üí        onDoubleClick={handleDoubleClick}
436‚Üí      >
437‚Üí        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
438‚Üí          {viewMode === 'plan' && showGrid && <GridRenderer />}
439‚Üí          {viewMode === 'plan' && showGrid && (
440‚Üí            <rect
441‚Üí              x={-100000} y={-100000}
442‚Üí              width={200000} height={200000}
443‚Üí              fill="url(#grid-major)"
444‚Üí              style={{ pointerEvents: 'none' }}
445‚Üí            />
446‚Üí          )}
447‚Üí          {modelTarget === 'roof' ? (
448‚Üí            roofSystem ? (
449‚Üí              <>
450‚Üí                {viewMode === 'plan' ? (
451‚Üí                  <>
452‚Üí                    <RoofRenderer roofSystem={roofSystem} selectedId={selectedId} selectedType={selectedType} />
453‚Üí                    <RoofSelectionOverlay
