 30‚Üífunction getSheetPreviewCacheKey(source) {
 31‚Üí  return [
 32‚Üí    source?.project?.id || 'project',
 33‚Üí    source?.project?.updatedAt || 'snapshot',
 34‚Üí    source?.activeFloorId || 'all',
 35‚Üí    SHEET_PREVIEW_OPTIONS.width,
