 41‚Üífunction renderSheetPreviewImage(source) {
 42‚Üí  const cacheKey = getSheetPreviewCacheKey(source);
 43‚Üí  if (!sheetPreviewCache.has(cacheKey)) {
 44‚Üí    sheetPreviewCache.set(cacheKey, import('@/three/viewer/renderToImage')
 45‚Üí      .then(({ renderSceneToImage }) => {
 46‚Üí        const imageUrl = renderSceneToImage(source.project, {
 47‚Üí          activeFloorId: source.activeFloorId,
 48‚Üí          width: SHEET_PREVIEW_OPTIONS.width,
 49‚Üí          height: SHEET_PREVIEW_OPTIONS.height,
 50‚Üí          preset: SHEET_PREVIEW_OPTIONS.preset,
 51‚Üí        });
 52‚Üí
 53‚Üí        return imageUrl
 54‚Üí          ? { status: 'ready', imageUrl }
 55‚Üí          : { status: 'empty', imageUrl: null };
 56‚Üí      })
 57‚Üí      .catch((error) => {
 58‚Üí        sheetPreviewCache.delete(cacheKey);
 59‚Üí        throw error;
 60‚Üí      }));
 61‚Üí  }
 62‚Üí
 63‚Üí  return sheetPreviewCache.get(cacheKey);
