 90‚Üífunction ThreePreviewViewportContent({ source }) {
 91‚Üí  const [previewState, setPreviewState] = useState({
 92‚Üí    status: 'loading',
 93‚Üí    imageUrl: null,
 94‚Üí  });
 95‚Üí
 96‚Üí  useEffect(() => {
 97‚Üí    if (!source?.project) {
 98‚Üí      setPreviewState({
 99‚Üí        status: 'empty',
100‚Üí        imageUrl: null,
101‚Üí      });
102‚Üí      return undefined;
103‚Üí    }
104‚Üí
105‚Üí    let cancelled = false;
106‚Üí    setPreviewState({
107‚Üí      status: 'loading',
108‚Üí      imageUrl: null,
109‚Üí    });
110‚Üí
111‚Üí    renderSheetPreviewImage(source)
112‚Üí      .then((result) => {
113‚Üí        if (cancelled) return;
114‚Üí        setPreviewState(result);
115‚Üí      })
116‚Üí      .catch((error) => {
117‚Üí        if (cancelled) return;
118‚Üí        console.error('Failed to render sheet 3D preview:', error);
119‚Üí        setPreviewState({
120‚Üí          status: 'error',
121‚Üí          imageUrl: null,
122‚Üí        });
123‚Üí      });
124‚Üí
125‚Üí    return () => { cancelled = true; };
126‚Üí  }, [source?.project, source?.project?.updatedAt, source?.activeFloorId]);
127‚Üí
128‚Üí  const { bounds } = source;
129‚Üí  const centerX = (bounds.minX + bounds.maxX) / 2;
130‚Üí  const centerY = (bounds.minY + bounds.maxY) / 2;
131‚Üí
132‚Üí  if (previewState.status !== 'ready' || !previewState.imageUrl) {
133‚Üí    const messages = {
134‚Üí      loading: 'Rendering 3D preview...',
135‚Üí      empty: 'No 3D geometry available.',
136‚Üí      error: '3D preview failed to render.',
137‚Üí    };
138‚Üí
139‚Üí    return (
140‚Üí      <text
141‚Üí        x={centerX}
142‚Üí        y={centerY}
143‚Üí        textAnchor="middle"
144‚Üí        fontSize={400}
145‚Üí        fill="#8899aa"
146‚Üí        pointerEvents="none"
147‚Üí      >
148‚Üí        {messages[previewState.status] || messages.loading}
149‚Üí      </text>
150‚Üí    );
151‚Üí  }
152‚Üí
153‚Üí  return (
154‚Üí    <image
155‚Üí      href={previewState.imageUrl}
156‚Üí      x={bounds.minX}
157‚Üí      y={bounds.minY}
158‚Üí      width={bounds.maxX - bounds.minX}
159‚Üí      height={bounds.maxY - bounds.minY}
160‚Üí      preserveAspectRatio="xMidYMid meet"
161‚Üí      pointerEvents="none"
162‚Üí    />
163‚Üí  );
164‚Üí}
